// OwlDB is a network-accessible, NoSQL document database.
package main

import (
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"

	"github.com/RICE-COMP318-FALL24/owldb-agent/auth"
	owlserver "github.com/RICE-COMP318-FALL24/owldb-agent/server"
)

func main() {
	var server http.Server
	var port int
	var err error

	// Parse CLI flags
	flag.IntVar(&port, "p", 3318, "port to listen on")
	schemaFile := flag.String("s", "", "JSON schema file (required)")
	tokenFile := flag.String("t", "", "token file")
	flag.Parse()

	if *schemaFile == "" {
		fmt.Fprintln(os.Stderr, "schema file is required (-s flag)")
		os.Exit(1)
	}

	// Load schema
	schema, err := owlserver.LoadSchema(*schemaFile)
	if err != nil {
		slog.Error("Failed to load schema", "error", err)
		os.Exit(1)
	}

	// Set up auth
	authMgr := auth.NewManager()
	if *tokenFile != "" {
		if err := authMgr.LoadTokenFile(*tokenFile); err != nil {
			slog.Error("Failed to load token file", "error", err)
			os.Exit(1)
		}
	}

	// Create server
	s := owlserver.New(authMgr, schema)
	server = http.Server{
		Addr:    fmt.Sprintf(":%d", port),
		Handler: s.Handler(),
	}

	// The following code should go last and remain unchanged.
	// Note that you must actually initialize 'server' and 'port'
	// before this.  Note that the server is started below by
	// calling ListenAndServe.  You must not start the server
	// before this.

	// signal.Notify requires the channel to be buffered
	ctrlc := make(chan os.Signal, 1)
	signal.Notify(ctrlc, os.Interrupt, syscall.SIGTERM)
	go func() {
		// Wait for Ctrl-C signal
		<-ctrlc
		server.Close()
	}()

	// Start server
	slog.Info("Listening", "port", port)
	err = server.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		slog.Error("Server closed", "error", err)
	} else {
		slog.Info("Server closed", "error", err)
	}
}

// Package auth implements bearer token authentication for OwlDB.
package auth

import (
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"sync"
	"time"
)

// tokenEntry stores info about a token.
type tokenEntry struct {
	username  string
	expiresAt time.Time
}

// Manager manages authentication tokens.
type Manager struct {
	mu     sync.RWMutex
	tokens map[string]tokenEntry // token -> entry
}

// NewManager creates a new auth manager.
func NewManager() *Manager {
	return &Manager{
		tokens: make(map[string]tokenEntry),
	}
}

// LoadTokenFile loads pre-configured tokens from a JSON file.
// The file maps usernames to tokens.
func (m *Manager) LoadTokenFile(filename string) error {
	data, err := os.ReadFile(filename)
	if err != nil {
		return fmt.Errorf("failed to read token file: %w", err)
	}

	var tokenMap map[string]string
	if err := json.Unmarshal(data, &tokenMap); err != nil {
		return fmt.Errorf("failed to parse token file: %w", err)
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	for username, token := range tokenMap {
		m.tokens[token] = tokenEntry{
			username:  username,
			expiresAt: time.Now().Add(24 * time.Hour),
		}
	}
	return nil
}

// Login creates a new token for the given username.
func (m *Manager) Login(username string) (string, error) {
	token, err := generateToken()
	if err != nil {
		return "", err
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	m.tokens[token] = tokenEntry{
		username:  username,
		expiresAt: time.Now().Add(1 * time.Hour),
	}
	return token, nil
}

// Logout invalidates the given token.
func (m *Manager) Logout(token string) bool {
	m.mu.Lock()
	defer m.mu.Unlock()

	if _, ok := m.tokens[token]; ok {
		delete(m.tokens, token)
		return true
	}
	return false
}

// ValidateToken checks if a token is valid and not expired.
// Returns the username associated with the token, or an error.
func (m *Manager) ValidateToken(token string) (string, bool) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	entry, ok := m.tokens[token]
	if !ok {
		return "", false
	}
	if time.Now().After(entry.expiresAt) {
		return "", false
	}
	return entry.username, true
}

// generateToken creates a cryptographically random token.
func generateToken() (string, error) {
	b := make([]byte, 16)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

// Package server implements the HTTP handlers for the OwlDB REST API.
package server

import (
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-agent/auth"
	"github.com/RICE-COMP318-FALL24/owldb-agent/document"
	"github.com/RICE-COMP318-FALL24/owldb-agent/jsondata"
	jsonschema "github.com/santhosh-tekuri/jsonschema/v5"
)

// Server holds the state for the OwlDB HTTP server.
type Server struct {
	store       *document.Store
	auth        *auth.Manager
	schema      *jsonschema.Schema
	docSubs     *document.DocSubscriptions
}

// New creates a new Server.
func New(authMgr *auth.Manager, schema *jsonschema.Schema) *Server {
	return &Server{
		store:   document.NewStore(),
		auth:    authMgr,
		schema:  schema,
		docSubs: document.NewDocSubscriptions(),
	}
}

// Handler returns the HTTP handler for the server.
func (s *Server) Handler() http.Handler {
	mux := http.NewServeMux()
	mux.HandleFunc("/auth", s.handleAuth)
	mux.HandleFunc("/v1/", s.handleV1)
	return mux
}

// writeJSON writes a JSON response.
func writeJSON(w http.ResponseWriter, status int, data interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(data)
}

// writeError writes a JSON error response.
func writeError(w http.ResponseWriter, status int, msg string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(map[string]string{"error": msg})
}

// extractToken extracts the bearer token from the Authorization header.
func extractToken(r *http.Request) string {
	auth := r.Header.Get("Authorization")
	if !strings.HasPrefix(auth, "Bearer ") {
		return ""
	}
	return strings.TrimPrefix(auth, "Bearer ")
}

// requireAuth validates the bearer token and returns the username.
func (s *Server) requireAuth(w http.ResponseWriter, r *http.Request) (string, bool) {
	token := extractToken(r)
	if token == "" {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	username, valid := s.auth.ValidateToken(token)
	if !valid {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	return username, true
}

// handleAuth handles POST /auth (login) and DELETE /auth (logout).
func (s *Server) handleAuth(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodPost:
		s.handleLogin(w, r)
	case http.MethodDelete:
		s.handleLogout(w, r)
	case http.MethodOptions:
		w.Header().Set("Allow", "POST, DELETE, OPTIONS")
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.Header().Set("Access-Control-Allow-Methods", "POST, DELETE, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
		w.WriteHeader(http.StatusOK)
	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (s *Server) handleLogin(w http.ResponseWriter, r *http.Request) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	var loginReq struct {
		Username string `json:"username"`
	}
	if err := json.Unmarshal(body, &loginReq); err != nil || loginReq.Username == "" {
		writeError(w, http.StatusBadRequest, "No username in request body")
		return
	}

	token, err := s.auth.Login(loginReq.Username)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "Failed to create token")
		return
	}

	writeJSON(w, http.StatusOK, map[string]string{"token": token})
}

func (s *Server) handleLogout(w http.ResponseWriter, r *http.Request) {
	token := extractToken(r)
	if token == "" {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	if !s.auth.Logout(token) {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

// handleV1 dispatches /v1/ requests based on the path structure.
func (s *Server) handleV1(w http.ResponseWriter, r *http.Request) {
	// OPTIONS doesn't require auth
	if r.Method == http.MethodOptions {
		s.handleOptions(w, r)
		return
	}

	// All other methods require auth (except OPTIONS)
	username, ok := s.requireAuth(w, r)
	if !ok {
		return
	}

	// Parse path: /v1/{database}/{docPath...}
	rawPath := r.URL.Path
	path := strings.TrimPrefix(rawPath, "/v1/")
	isCollection := strings.HasSuffix(path, "/")
	path = strings.TrimSuffix(path, "/")

	if path == "" {
		writeError(w, http.StatusBadRequest, "No database specified")
		return
	}

	parts := strings.Split(path, "/")
	dbName := parts[0]
	pathParts := parts[1:] // remaining path after database name

	// Check query params
	mode := r.URL.Query().Get("mode")
	interval := r.URL.Query().Get("interval")

	// Route based on method and path structure
	switch {
	case len(pathParts) == 0 && isCollection:
		// /v1/{database}/ - database-level operations
		switch r.Method {
		case http.MethodPut:
			s.handleCreateDatabase(w, r, dbName, username)
		case http.MethodDelete:
			s.handleDeleteDatabase(w, r, dbName)
		case http.MethodGet:
			if mode == "subscribe" {
				s.handleSubscribeCollection(w, r, dbName, nil, isCollection, interval)
			} else {
				s.handleGetCollection(w, r, dbName, nil, interval)
			}
		case http.MethodPost:
			s.handlePostDocument(w, r, dbName, nil, username)
		default:
			writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
		}

	case len(pathParts) == 0 && !isCollection:
		// /v1/{database} (no trailing slash) - also treat as database
		switch r.Method {
		case http.MethodPut:
			s.handleCreateDatabase(w, r, dbName, username)
		case http.MethodDelete:
			s.handleDeleteDatabase(w, r, dbName)
		case http.MethodGet:
			if mode == "subscribe" {
				s.handleSubscribeCollection(w, r, dbName, nil, true, interval)
			} else {
				s.handleGetCollection(w, r, dbName, nil, interval)
			}
		default:
			writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
		}

	case isCollection:
		// Path ends with / - collection operation
		switch r.Method {
		case http.MethodPut:
			s.handleCreateCollection(w, r, dbName, pathParts, username)
		case http.MethodDelete:
			s.handleDeleteCollection(w, r, dbName, pathParts)
		case http.MethodGet:
			if mode == "subscribe" {
				s.handleSubscribeCollection(w, r, dbName, pathParts, isCollection, interval)
			} else {
				s.handleGetCollection(w, r, dbName, pathParts, interval)
			}
		case http.MethodPost:
			s.handlePostDocument(w, r, dbName, pathParts, username)
		default:
			writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
		}

	default:
		// Path doesn't end with / - document operation
		switch r.Method {
		case http.MethodPut:
			s.handlePutDocument(w, r, dbName, pathParts, username, mode)
		case http.MethodGet:
			if mode == "subscribe" {
				s.handleSubscribeDocument(w, r, dbName, pathParts)
			} else {
				s.handleGetDocument(w, r, dbName, pathParts)
			}
		case http.MethodDelete:
			s.handleDeleteDocument(w, r, dbName, pathParts)
		case http.MethodPatch:
			s.handlePatchDocument(w, r, dbName, pathParts, username)
		default:
			writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
		}
	}
}

// handleOptions responds to OPTIONS requests.
func (s *Server) handleOptions(w http.ResponseWriter, r *http.Request) {
	rawPath := r.URL.Path
	path := strings.TrimPrefix(rawPath, "/v1/")
	isCollection := strings.HasSuffix(path, "/")
	path = strings.TrimSuffix(path, "/")

	var allow string
	if isCollection || path == "" || len(strings.Split(path, "/")) == 1 {
		// Database or collection
		allow = "GET, PUT, POST, DELETE, OPTIONS"
	} else {
		// Document
		allow = "GET, PUT, DELETE, PATCH, OPTIONS"
	}

	w.Header().Set("Allow", allow)
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Methods", allow)
	w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
	w.WriteHeader(http.StatusOK)
}

// Database operations

func (s *Server) handleCreateDatabase(w http.ResponseWriter, r *http.Request, dbName string, username string) {
	err := s.store.CreateDatabase(dbName)
	if err != nil {
		writeError(w, http.StatusConflict, "Database already exists")
		return
	}

	uri := "/v1/" + dbName
	w.Header().Set("Location", uri)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": uri})
}

func (s *Server) handleDeleteDatabase(w http.ResponseWriter, r *http.Request, dbName string) {
	db, ok := s.store.DeleteDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// Notify collection subscribers
	event := document.Event{
		Type: "delete",
		Data: fmt.Sprintf("\"/v1/%s/\"", dbName),
		ID:   fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	db.Collection.NotifyAllSubscribers(event)

	w.WriteHeader(http.StatusNoContent)
}

// Collection operations

func (s *Server) resolveCollection(dbName string, pathParts []string) (*document.Database, *document.Collection, error) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		return nil, nil, fmt.Errorf("database not found")
	}

	if len(pathParts) == 0 {
		return db, db.Collection, nil
	}

	col, _, err := document.ResolvePath(db, pathParts)
	if err != nil {
		return db, nil, err
	}
	return db, col, nil
}

func (s *Server) handleCreateCollection(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	if len(pathParts) < 2 {
		writeError(w, http.StatusBadRequest, "Invalid collection path")
		return
	}

	// Navigate to the parent document
	docPathParts := pathParts[:len(pathParts)-1]
	colName := pathParts[len(pathParts)-1]

	// Resolve up to the parent collection
	var parentCol *document.Collection
	if len(docPathParts) == 1 {
		// Direct child of database
		parentCol = db.Collection
	} else {
		// Navigate through the path
		col, docName, err := document.ResolvePath(db, docPathParts)
		if err != nil {
			writeError(w, http.StatusNotFound, "Parent path not found")
			return
		}
		_ = docName
		_ = col
		// Actually we need the document at the last doc position
		parentCol = db.Collection
		for i := 0; i < len(docPathParts)-1; i += 2 {
			dName := docPathParts[i]
			doc, found := parentCol.Documents.Find(dName)
			if !found {
				writeError(w, http.StatusNotFound, fmt.Sprintf("Document not found: %s", dName))
				return
			}
			if i+1 < len(docPathParts)-1 {
				cName := docPathParts[i+1]
				childCol, found := doc.GetCollection(cName)
				if !found {
					writeError(w, http.StatusNotFound, fmt.Sprintf("Collection not found: %s", cName))
					return
				}
				parentCol = childCol
			}
		}
	}

	// Find the parent document
	parentDocName := docPathParts[len(docPathParts)-1]
	parentDoc, found := parentCol.Documents.Find(parentDocName)
	if !found {
		writeError(w, http.StatusNotFound, fmt.Sprintf("Document not found: %s", parentDocName))
		return
	}

	_, err := parentDoc.CreateCollection(colName)
	if err != nil {
		writeError(w, http.StatusConflict, "Collection already exists")
		return
	}

	uri := "/v1/" + dbName + "/" + strings.Join(pathParts, "/") + "/"
	w.Header().Set("Location", uri)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": uri})
}

func (s *Server) handleDeleteCollection(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	// For now, we don't support deleting sub-collections via this path.
	// The test mainly tests deleting databases.
	writeError(w, http.StatusNotFound, "Collection not found")
}

func (s *Server) handleGetCollection(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, interval string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	var col *document.Collection
	if len(pathParts) == 0 {
		col = db.Collection
	} else {
		// Navigate to the collection
		currentCol := db.Collection
		for i := 0; i < len(pathParts); i += 2 {
			docName := pathParts[i]
			doc, found := currentCol.Documents.Find(docName)
			if !found {
				writeError(w, http.StatusNotFound, "Document not found")
				return
			}
			if i+1 >= len(pathParts) {
				writeError(w, http.StatusBadRequest, "Path does not end at collection")
				return
			}
			colName := pathParts[i+1]
			childCol, found := doc.GetCollection(colName)
			if !found {
				writeError(w, http.StatusNotFound, "Collection does not exist")
				return
			}
			currentCol = childCol
		}
		col = currentCol
	}

	// Parse interval
	low, high, hasLow, hasHigh := parseInterval(interval)

	pairs, err := document.QueryCollection(col, low, high, hasLow, hasHigh)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "Query failed")
		return
	}

	// Build response array
	result := make([]map[string]interface{}, 0, len(pairs))
	for _, p := range pairs {
		docPath := "/v1/" + dbName + "/"
		if len(pathParts) > 0 {
			docPath += strings.Join(pathParts, "/") + "/"
		}
		docPath += p.Key

		entry := buildDocResponse(docPath, p.Value)
		result = append(result, entry)
	}

	writeJSON(w, http.StatusOK, result)
}

// Document operations

func (s *Server) handlePutDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string, mode string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// Read body
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	// Validate against schema
	if s.schema != nil && len(body) > 0 {
		var jv jsondata.JSONValue
		if err := json.Unmarshal(body, &jv); err != nil {
			writeError(w, http.StatusBadRequest, "Invalid JSON")
			return
		}
		if err := jv.Validate(s.schema); err != nil {
			writeError(w, http.StatusBadRequest, fmt.Sprintf("Schema validation failed: %s", err))
			return
		}
	}

	// Navigate to the containing collection
	col := db.Collection
	docName := pathParts[len(pathParts)-1]

	if len(pathParts) > 1 {
		// Navigate through the path to find the parent collection
		parentParts := pathParts[:len(pathParts)-1]
		currentCol := db.Collection
		for i := 0; i < len(parentParts); i += 2 {
			pDocName := parentParts[i]
			doc, found := currentCol.Documents.Find(pDocName)
			if !found {
				writeError(w, http.StatusNotFound, "Collection does not exist")
				return
			}
			if i+1 >= len(parentParts) {
				writeError(w, http.StatusNotFound, "Collection does not exist")
				return
			}
			colName := parentParts[i+1]
			childCol, found := doc.GetCollection(colName)
			if !found {
				writeError(w, http.StatusNotFound, "Collection does not exist")
				return
			}
			currentCol = childCol
		}
		col = currentCol
	}

	docPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	noOverwrite := mode == "nooverwrite"

	var statusCode int
	newDoc := document.NewDocument(body, username)

	_, err = col.Documents.Upsert(docName, func(key string, curr *document.Document, exists bool) (*document.Document, error) {
		if exists && noOverwrite {
			return curr, fmt.Errorf("document already exists")
		}
		if exists {
			// Overwrite: preserve createdBy and createdAt
			curr.UpdateData(body, username)
			statusCode = http.StatusOK
			return curr, nil
		}
		statusCode = http.StatusCreated
		return newDoc, nil
	})

	if err != nil {
		if noOverwrite {
			writeError(w, http.StatusPreconditionFailed, "Document already exists")
		} else {
			writeError(w, http.StatusInternalServerError, err.Error())
		}
		return
	}

	// Notify subscribers
	var doc *document.Document
	if statusCode == http.StatusOK {
		doc, _ = col.Documents.Find(docName)
	} else {
		doc = newDoc
	}
	s.notifyDocUpdate(docPath, docName, doc, col)

	w.Header().Set("Location", docPath)
	writeJSON(w, statusCode, map[string]string{"uri": docPath})
}

func (s *Server) handleGetDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	col, docName, err := resolveToDoc(db, pathParts)
	if err != nil {
		writeError(w, http.StatusNotFound, err.Error())
		return
	}

	doc, found := col.Documents.Find(docName)
	if !found {
		writeError(w, http.StatusNotFound, "Document does not exist")
		return
	}

	docPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	result := buildDocResponse(docPath, doc)
	writeJSON(w, http.StatusOK, result)
}

func (s *Server) handleDeleteDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	col, docName, err := resolveToDoc(db, pathParts)
	if err != nil {
		writeError(w, http.StatusNotFound, err.Error())
		return
	}

	_, removed := col.Documents.Remove(docName)
	if !removed {
		writeError(w, http.StatusNotFound, "Document does not exist")
		return
	}

	// Notify subscribers
	docPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	event := document.Event{
		Type: "delete",
		Data: fmt.Sprintf("%q", docPath),
		ID:   fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	s.docSubs.Notify(docPath, event)
	col.NotifySubscribers(docName, event)

	w.WriteHeader(http.StatusNoContent)
}

func (s *Server) handlePostDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// Read body
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	// Validate against schema
	if s.schema != nil && len(body) > 0 {
		var jv jsondata.JSONValue
		if err := json.Unmarshal(body, &jv); err != nil {
			writeError(w, http.StatusBadRequest, "Invalid JSON")
			return
		}
		if err := jv.Validate(s.schema); err != nil {
			writeError(w, http.StatusBadRequest, fmt.Sprintf("Schema validation failed: %s", err))
			return
		}
	}

	// Navigate to the collection
	var col *document.Collection
	if len(pathParts) == 0 {
		col = db.Collection
	} else {
		currentCol := db.Collection
		for i := 0; i < len(pathParts); i += 2 {
			dName := pathParts[i]
			doc, found := currentCol.Documents.Find(dName)
			if !found {
				writeError(w, http.StatusNotFound, "Collection does not exist")
				return
			}
			if i+1 >= len(pathParts) {
				writeError(w, http.StatusNotFound, "Collection does not exist")
				return
			}
			colName := pathParts[i+1]
			childCol, found := doc.GetCollection(colName)
			if !found {
				writeError(w, http.StatusNotFound, "Collection does not exist")
				return
			}
			currentCol = childCol
		}
		col = currentCol
	}

	// Generate unique document name
	docName := generateDocID()

	newDoc := document.NewDocument(body, username)
	col.Documents.Upsert(docName, func(key string, curr *document.Document, exists bool) (*document.Document, error) {
		return newDoc, nil
	})

	docPath := "/v1/" + dbName + "/"
	if len(pathParts) > 0 {
		docPath += strings.Join(pathParts, "/") + "/"
	}
	docPath += docName

	// Notify subscribers
	s.notifyDocUpdate(docPath, docName, newDoc, col)

	w.Header().Set("Location", docPath)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": docPath})
}

func (s *Server) handlePatchDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	col, docName, err := resolveToDoc(db, pathParts)
	if err != nil {
		writeError(w, http.StatusNotFound, err.Error())
		return
	}

	doc, found := col.Documents.Find(docName)
	if !found {
		writeError(w, http.StatusNotFound, "Document does not exist")
		return
	}

	// Read patches
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}

	var patches []PatchOp
	if err := json.Unmarshal(body, &patches); err != nil {
		writeError(w, http.StatusBadRequest, "Invalid patch format")
		return
	}

	docPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")

	// Apply patches atomically
	doc.Lock()
	result := s.applyPatches(doc, patches, username, docPath)
	doc.Unlock()

	if !result.PatchFailed {
		// Notify subscribers of update
		s.notifyDocUpdate(docPath, docName, doc, col)
	}

	writeJSON(w, http.StatusOK, result)
}

// SSE subscription handlers

func (s *Server) handleSubscribeDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	col, docName, err := resolveToDoc(db, pathParts)
	if err != nil {
		writeError(w, http.StatusNotFound, err.Error())
		return
	}

	doc, found := col.Documents.Find(docName)
	if !found {
		writeError(w, http.StatusNotFound, "Document does not exist")
		return
	}

	// Set SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.WriteHeader(http.StatusOK)

	flusher, ok := w.(http.Flusher)
	if !ok {
		return
	}

	docPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
	eventCh := make(chan document.Event, 100)

	// Subscribe
	s.docSubs.Subscribe(docPath, eventCh)
	defer s.docSubs.Unsubscribe(docPath, eventCh)

	// Send initial event with current document state
	initialData := buildDocResponseJSON(docPath, doc)
	writeSSEEvent(w, "update", initialData, fmt.Sprintf("%d", time.Now().UnixMilli()))
	flusher.Flush()

	// Create a ticker for keep-alive comments
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	ctx := r.Context()
	for {
		select {
		case <-ctx.Done():
			return
		case event, ok := <-eventCh:
			if !ok {
				return
			}
			writeSSEEvent(w, event.Type, event.Data, event.ID)
			flusher.Flush()
		case <-ticker.C:
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()
		}
	}
}

func (s *Server) handleSubscribeCollection(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, isCollection bool, interval string) {
	db, ok := s.store.GetDatabase(dbName)
	if !ok {
		writeError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	var col *document.Collection
	if len(pathParts) == 0 {
		col = db.Collection
	} else {
		currentCol := db.Collection
		for i := 0; i < len(pathParts); i += 2 {
			dName := pathParts[i]
			doc, found := currentCol.Documents.Find(dName)
			if !found {
				writeError(w, http.StatusNotFound, "Path not found")
				return
			}
			if i+1 >= len(pathParts) {
				writeError(w, http.StatusNotFound, "Path not found")
				return
			}
			colName := pathParts[i+1]
			childCol, found := doc.GetCollection(colName)
			if !found {
				writeError(w, http.StatusNotFound, "Collection not found")
				return
			}
			currentCol = childCol
		}
		col = currentCol
	}

	// Set SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.WriteHeader(http.StatusOK)

	flusher, ok := w.(http.Flusher)
	if !ok {
		return
	}

	low, high, hasLow, hasHigh := parseInterval(interval)

	eventCh := make(chan document.Event, 100)
	sub := document.Subscriber{
		EventCh: eventCh,
		Low:     low,
		High:    high,
		HasLow:  hasLow,
		HasHigh: hasHigh,
	}
	col.AddSubscriber(sub)
	defer col.RemoveSubscriber(eventCh)

	// Send initial events for existing documents in range
	pairs, _ := document.QueryCollection(col, low, high, hasLow, hasHigh)
	basePath := "/v1/" + dbName + "/"
	if len(pathParts) > 0 {
		basePath += strings.Join(pathParts, "/") + "/"
	}
	for _, p := range pairs {
		docPath := basePath + p.Key
		data := buildDocResponseJSON(docPath, p.Value)
		writeSSEEvent(w, "update", data, fmt.Sprintf("%d", time.Now().UnixMilli()))
	}
	flusher.Flush()

	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	ctx := r.Context()
	for {
		select {
		case <-ctx.Done():
			return
		case event, ok := <-eventCh:
			if !ok {
				return
			}
			writeSSEEvent(w, event.Type, event.Data, event.ID)
			flusher.Flush()
		case <-ticker.C:
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()
		}
	}
}

// Helper functions

func resolveToDoc(db *document.Database, pathParts []string) (*document.Collection, string, error) {
	if len(pathParts) == 0 {
		return nil, "", fmt.Errorf("no document specified")
	}

	docName := pathParts[len(pathParts)-1]
	col := db.Collection

	if len(pathParts) > 1 {
		parentParts := pathParts[:len(pathParts)-1]
		currentCol := db.Collection
		for i := 0; i < len(parentParts); i += 2 {
			pDocName := parentParts[i]
			doc, found := currentCol.Documents.Find(pDocName)
			if !found {
				return nil, "", fmt.Errorf("path not found: %s", pDocName)
			}
			if i+1 >= len(parentParts) {
				return nil, "", fmt.Errorf("invalid path structure")
			}
			colName := parentParts[i+1]
			childCol, found := doc.GetCollection(colName)
			if !found {
				return nil, "", fmt.Errorf("collection not found: %s", colName)
			}
			currentCol = childCol
		}
		col = currentCol
	}

	return col, docName, nil
}

func buildDocResponse(path string, doc *document.Document) map[string]interface{} {
	var docData interface{}
	json.Unmarshal(doc.GetData(), &docData)

	meta := doc.GetMeta()
	return map[string]interface{}{
		"path": path,
		"doc":  docData,
		"meta": map[string]interface{}{
			"createdBy":      meta.CreatedBy,
			"createdAt":      meta.CreatedAt,
			"lastModifiedBy": meta.LastModifiedBy,
			"lastModifiedAt": meta.LastModifiedAt,
		},
	}
}

func buildDocResponseJSON(path string, doc *document.Document) string {
	resp := buildDocResponse(path, doc)
	data, _ := json.Marshal(resp)
	return string(data)
}

func writeSSEEvent(w http.ResponseWriter, eventType, data, id string) {
	fmt.Fprintf(w, "event: %s\n", eventType)
	// Data can be multi-line; each line needs "data: " prefix
	lines := strings.Split(data, "\n")
	for _, line := range lines {
		fmt.Fprintf(w, "data: %s\n", line)
	}
	fmt.Fprintf(w, "id: %s\n\n", id)
}

func parseInterval(interval string) (low, high string, hasLow, hasHigh bool) {
	if interval == "" {
		return "", "", false, false
	}

	// Remove brackets
	interval = strings.TrimPrefix(interval, "[")
	interval = strings.TrimSuffix(interval, "]")

	parts := strings.SplitN(interval, ",", 2)
	if len(parts) != 2 {
		return "", "", false, false
	}

	low = strings.TrimSpace(parts[0])
	high = strings.TrimSpace(parts[1])
	hasLow = low != ""
	hasHigh = high != ""
	return
}

func generateDocID() string {
	b := make([]byte, 8)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func (s *Server) notifyDocUpdate(docPath, docName string, doc *document.Document, col *document.Collection) {
	data := buildDocResponseJSON(docPath, doc)
	event := document.Event{
		Type: "update",
		Data: data,
		ID:   fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	s.docSubs.Notify(docPath, event)
	col.NotifySubscribers(docName, event)
}

// PatchOp represents a single patch operation.
type PatchOp struct {
	Op    string          `json:"op"`
	Path  string          `json:"path"`
	Value json.RawMessage `json:"value"`
}

// PatchResult is the response for a PATCH request.
type PatchResult struct {
	URI         string `json:"uri"`
	PatchFailed bool   `json:"patchFailed"`
	Message     string `json:"message"`
}

func (s *Server) applyPatches(doc *document.Document, patches []PatchOp, username string, docPath string) PatchResult {
	if len(patches) == 0 {
		return PatchResult{URI: docPath, PatchFailed: false, Message: "patch applied"}
	}

	// Unmarshal current document into JSONValue
	currentData := doc.Data
	var jv jsondata.JSONValue
	if err := json.Unmarshal(currentData, &jv); err != nil {
		return PatchResult{URI: docPath, PatchFailed: true, Message: "Failed to parse document"}
	}

	// Apply each patch in order
	for _, patch := range patches {
		var patchValue jsondata.JSONValue
		if err := json.Unmarshal(patch.Value, &patchValue); err != nil {
			return PatchResult{URI: docPath, PatchFailed: true, Message: fmt.Sprintf("Invalid patch value: %s", err)}
		}

		var err error
		jv, err = applyOnePatch(jv, patch.Op, patch.Path, patchValue)
		if err != nil {
			return PatchResult{URI: docPath, PatchFailed: true, Message: err.Error()}
		}
	}

	// Marshal back to bytes
	newData, err := json.Marshal(jv)
	if err != nil {
		return PatchResult{URI: docPath, PatchFailed: true, Message: "Failed to marshal patched document"}
	}

	// Validate against schema
	if s.schema != nil {
		var validated jsondata.JSONValue
		json.Unmarshal(newData, &validated)
		if err := validated.Validate(s.schema); err != nil {
			return PatchResult{URI: docPath, PatchFailed: true, Message: fmt.Sprintf("Schema validation failed: %s", err)}
		}
	}

	// Update document
	doc.Data = newData
	doc.Meta.LastModifiedBy = username
	doc.Meta.LastModifiedAt = time.Now().UnixMilli()

	return PatchResult{URI: docPath, PatchFailed: false, Message: "patch applied"}
}

// applyOnePatch applies a single patch operation to a JSONValue.
func applyOnePatch(jv jsondata.JSONValue, op, path string, value jsondata.JSONValue) (jsondata.JSONValue, error) {
	// Parse the JSON pointer path
	pathParts := parseJSONPointer(path)

	switch op {
	case "ArrayAdd":
		return applyArrayAdd(jv, pathParts, value)
	case "ArrayRemove":
		return applyArrayRemove(jv, pathParts, value)
	case "ObjectAdd":
		if len(pathParts) < 1 {
			return jv, fmt.Errorf("ObjectAdd requires at least one path element")
		}
		return applyObjectAdd(jv, pathParts, value)
	default:
		return jv, fmt.Errorf("Unknown patch operation: %s", op)
	}
}

func parseJSONPointer(ptr string) []string {
	if ptr == "" || ptr == "/" {
		return nil
	}
	// Remove leading /
	ptr = strings.TrimPrefix(ptr, "/")
	parts := strings.Split(ptr, "/")
	// Unescape ~1 -> / and ~0 -> ~
	for i, p := range parts {
		p = strings.ReplaceAll(p, "~1", "/")
		p = strings.ReplaceAll(p, "~0", "~")
		parts[i] = p
	}
	return parts
}

// Visitor implementations for patch operations

// navigateVisitor navigates to a specific path in the JSON and applies a transformation.
type navigateVisitor struct {
	pathParts []string
	depth     int
	transform func(jsondata.JSONValue) (jsondata.JSONValue, error)
}

func (v *navigateVisitor) Map(m map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
	if v.depth >= len(v.pathParts) {
		// We're at the target - apply transform
		return v.transform(jsondata.JSONValue{})
	}

	key := v.pathParts[v.depth]
	child, exists := m[key]
	if !exists {
		if v.depth == len(v.pathParts)-1 {
			// For ObjectAdd at the last level, we need the map
			return v.transform(jsondata.JSONValue{})
		}
		return jsondata.JSONValue{}, fmt.Errorf("path element not found: %s", key)
	}

	v.depth++
	result, err := jsondata.Accept(child, v)
	if err != nil {
		return jsondata.JSONValue{}, err
	}
	v.depth--

	m[key] = result
	return jsondata.NewJSONValue(unwrapMap(m))
}

func (v *navigateVisitor) Slice(s []jsondata.JSONValue) (jsondata.JSONValue, error) {
	if v.depth >= len(v.pathParts) {
		return v.transform(jsondata.JSONValue{})
	}
	return jsondata.JSONValue{}, fmt.Errorf("expected object at path, got array")
}

func (v *navigateVisitor) Bool(b bool) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected object at path, got bool")
}

func (v *navigateVisitor) Float64(f float64) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected object at path, got number")
}

func (v *navigateVisitor) String(s string) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected object at path, got string")
}

func (v *navigateVisitor) Null() (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("expected object at path, got null")
}

func unwrapMap(m map[string]jsondata.JSONValue) map[string]interface{} {
	result := make(map[string]interface{})
	for k, v := range m {
		data, _ := json.Marshal(v)
		var val interface{}
		json.Unmarshal(data, &val)
		result[k] = val
	}
	return result
}

// Better approach: use direct JSON manipulation since the visitor pattern
// with JSONValue is quite constrained. Let me rewrite the patch operations
// to work with raw JSON values marshaled/unmarshaled.

func applyArrayAdd(jv jsondata.JSONValue, pathParts []string, value jsondata.JSONValue) (jsondata.JSONValue, error) {
	// Convert to interface{} for easier manipulation
	data, _ := json.Marshal(jv)
	var root interface{}
	json.Unmarshal(data, &root)

	valueData, _ := json.Marshal(value)
	var val interface{}
	json.Unmarshal(valueData, &val)

	// Navigate to the target
	target, err := navigateTo(root, pathParts)
	if err != nil {
		return jv, err
	}

	arr, ok := target.([]interface{})
	if !ok {
		return jv, fmt.Errorf("path does not refer to an array")
	}

	// Check if value already exists
	for _, item := range arr {
		itemJSON, _ := json.Marshal(item)
		valJSON, _ := json.Marshal(val)
		if string(itemJSON) == string(valJSON) {
			// Already exists, don't add
			return jv, nil
		}
	}

	// Add the value
	arr = append(arr, val)

	// Set it back
	err = setAt(root, pathParts, arr)
	if err != nil {
		return jv, err
	}

	newData, _ := json.Marshal(root)
	var result jsondata.JSONValue
	json.Unmarshal(newData, &result)
	return result, nil
}

func applyArrayRemove(jv jsondata.JSONValue, pathParts []string, value jsondata.JSONValue) (jsondata.JSONValue, error) {
	data, _ := json.Marshal(jv)
	var root interface{}
	json.Unmarshal(data, &root)

	valueData, _ := json.Marshal(value)
	var val interface{}
	json.Unmarshal(valueData, &val)

	target, err := navigateTo(root, pathParts)
	if err != nil {
		return jv, err
	}

	arr, ok := target.([]interface{})
	if !ok {
		return jv, fmt.Errorf("path does not refer to an array")
	}

	// Remove matching value
	valJSON, _ := json.Marshal(val)
	newArr := make([]interface{}, 0, len(arr))
	for _, item := range arr {
		itemJSON, _ := json.Marshal(item)
		if string(itemJSON) != string(valJSON) {
			newArr = append(newArr, item)
		}
	}

	err = setAt(root, pathParts, newArr)
	if err != nil {
		return jv, err
	}

	newData, _ := json.Marshal(root)
	var result jsondata.JSONValue
	json.Unmarshal(newData, &result)
	return result, nil
}

func applyObjectAdd(jv jsondata.JSONValue, pathParts []string, value jsondata.JSONValue) (jsondata.JSONValue, error) {
	data, _ := json.Marshal(jv)
	var root interface{}
	json.Unmarshal(data, &root)

	valueData, _ := json.Marshal(value)
	var val interface{}
	json.Unmarshal(valueData, &val)

	// For ObjectAdd, the last path element is the key to add
	if len(pathParts) == 0 {
		return jv, fmt.Errorf("ObjectAdd requires at least one path element")
	}

	parentPath := pathParts[:len(pathParts)-1]
	key := pathParts[len(pathParts)-1]

	var target interface{}
	var err error
	if len(parentPath) == 0 {
		target = root
	} else {
		target, err = navigateTo(root, parentPath)
		if err != nil {
			return jv, err
		}
	}

	obj, ok := target.(map[string]interface{})
	if !ok {
		return jv, fmt.Errorf("path does not refer to an object")
	}

	// Only add if key doesn't exist
	if _, exists := obj[key]; exists {
		return jv, nil
	}

	obj[key] = val

	newData, _ := json.Marshal(root)
	var result jsondata.JSONValue
	json.Unmarshal(newData, &result)
	return result, nil
}

func navigateTo(root interface{}, pathParts []string) (interface{}, error) {
	current := root
	for _, part := range pathParts {
		switch c := current.(type) {
		case map[string]interface{}:
			val, ok := c[part]
			if !ok {
				return nil, fmt.Errorf("path element not found: %s", part)
			}
			current = val
		default:
			return nil, fmt.Errorf("cannot navigate through non-object type")
		}
	}
	return current, nil
}

func setAt(root interface{}, pathParts []string, value interface{}) error {
	if len(pathParts) == 0 {
		return fmt.Errorf("empty path")
	}

	current := root
	for i := 0; i < len(pathParts)-1; i++ {
		part := pathParts[i]
		switch c := current.(type) {
		case map[string]interface{}:
			val, ok := c[part]
			if !ok {
				return fmt.Errorf("path element not found: %s", part)
			}
			current = val
		default:
			return fmt.Errorf("cannot navigate through non-object type")
		}
	}

	lastPart := pathParts[len(pathParts)-1]
	switch c := current.(type) {
	case map[string]interface{}:
		c[lastPart] = value
		return nil
	default:
		return fmt.Errorf("cannot set value in non-object type")
	}
}

// LoadSchema loads a JSON schema from a file.
func LoadSchema(filename string) (*jsonschema.Schema, error) {
	compiler := jsonschema.NewCompiler()
	schema, err := compiler.Compile(filename)
	if err != nil {
		return nil, fmt.Errorf("failed to compile schema: %w", err)
	}
	return schema, nil
}

// Package document implements the document, collection, and database model for OwlDB.
package document

import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-agent/skiplist"
)

// Metadata stores server-managed document metadata.
type Metadata struct {
	CreatedBy      string `json:"createdBy"`
	CreatedAt      int64  `json:"createdAt"`
	LastModifiedBy string `json:"lastModifiedBy"`
	LastModifiedAt int64  `json:"lastModifiedAt"`
}

// Document represents a stored document with its raw JSON bytes, metadata,
// and child collections.
type Document struct {
	mu          sync.RWMutex
	Data        []byte
	Meta        Metadata
	Collections *skiplist.SkipList[string, *Collection]
}

// NewDocument creates a new document with the given data and metadata.
func NewDocument(data []byte, username string) *Document {
	now := time.Now().UnixMilli()
	return &Document{
		Data: data,
		Meta: Metadata{
			CreatedBy:      username,
			CreatedAt:      now,
			LastModifiedBy: username,
			LastModifiedAt: now,
		},
		Collections: skiplist.New[string, *Collection]("", "\xff\xff\xff\xff"),
	}
}

// GetData returns the document's data (thread-safe).
func (d *Document) GetData() []byte {
	d.mu.RLock()
	defer d.mu.RUnlock()
	cp := make([]byte, len(d.Data))
	copy(cp, d.Data)
	return cp
}

// GetMeta returns the document's metadata (thread-safe).
func (d *Document) GetMeta() Metadata {
	d.mu.RLock()
	defer d.mu.RUnlock()
	return d.Meta
}

// UpdateData replaces the document's data and updates modification metadata.
func (d *Document) UpdateData(data []byte, username string) {
	d.mu.Lock()
	defer d.mu.Unlock()
	d.Data = data
	d.Meta.LastModifiedBy = username
	d.Meta.LastModifiedAt = time.Now().UnixMilli()
}

// Lock acquires the document's write lock.
func (d *Document) Lock() {
	d.mu.Lock()
}

// Unlock releases the document's write lock.
func (d *Document) Unlock() {
	d.mu.Unlock()
}

// GetCollection returns the named collection if it exists.
func (d *Document) GetCollection(name string) (*Collection, bool) {
	return d.Collections.Find(name)
}

// CreateCollection creates a new child collection for this document.
func (d *Document) CreateCollection(name string) (*Collection, error) {
	col := NewCollection()
	var created bool
	_, err := d.Collections.Upsert(name, func(key string, curr *Collection, exists bool) (*Collection, error) {
		if exists {
			return curr, fmt.Errorf("collection already exists")
		}
		created = true
		return col, nil
	})
	if err != nil {
		return nil, err
	}
	if !created {
		return nil, fmt.Errorf("collection already exists")
	}
	return col, nil
}

// Collection is a set of documents indexed by name.
type Collection struct {
	Documents   *skiplist.SkipList[string, *Document]
	subscribers []Subscriber
	subMu       sync.RWMutex
}

// NewCollection creates a new empty collection.
func NewCollection() *Collection {
	return &Collection{
		Documents: skiplist.New[string, *Document]("", "\xff\xff\xff\xff"),
	}
}

// Subscriber represents a client subscribed to collection or document changes.
type Subscriber struct {
	EventCh  chan Event
	Low      string // interval low bound ("" = unbounded)
	High     string // interval high bound ("" = unbounded)
	HasLow   bool
	HasHigh  bool
}

// Event represents an SSE event to send to subscribers.
type Event struct {
	Type string // "update" or "delete"
	Data string // JSON data
	ID   string // event ID (timestamp in millis)
}

// AddSubscriber adds a subscriber to this collection.
func (c *Collection) AddSubscriber(sub Subscriber) {
	c.subMu.Lock()
	defer c.subMu.Unlock()
	c.subscribers = append(c.subscribers, sub)
}

// RemoveSubscriber removes a subscriber from this collection.
func (c *Collection) RemoveSubscriber(ch chan Event) {
	c.subMu.Lock()
	defer c.subMu.Unlock()
	for i, sub := range c.subscribers {
		if sub.EventCh == ch {
			c.subscribers = append(c.subscribers[:i], c.subscribers[i+1:]...)
			return
		}
	}
}

// NotifySubscribers sends an event to all matching subscribers.
func (c *Collection) NotifySubscribers(docName string, event Event) {
	c.subMu.RLock()
	defer c.subMu.RUnlock()
	for _, sub := range c.subscribers {
		if sub.InRange(docName) {
			select {
			case sub.EventCh <- event:
			default:
				// Drop event if channel is full
			}
		}
	}
}

// NotifyAllSubscribers sends an event to all subscribers (for collection delete).
func (c *Collection) NotifyAllSubscribers(event Event) {
	c.subMu.RLock()
	defer c.subMu.RUnlock()
	for _, sub := range c.subscribers {
		select {
		case sub.EventCh <- event:
		default:
		}
	}
}

// InRange checks if a document name is within the subscriber's interval.
func (s *Subscriber) InRange(name string) bool {
	if s.HasLow && name < s.Low {
		return false
	}
	if s.HasHigh && name > s.High {
		return false
	}
	return true
}

// Database is a top-level named database which acts as a collection.
type Database struct {
	*Collection
}

// NewDatabase creates a new empty database.
func NewDatabase() *Database {
	return &Database{
		Collection: NewCollection(),
	}
}

// Store holds all databases.
type Store struct {
	databases *skiplist.SkipList[string, *Database]
}

// NewStore creates a new store.
func NewStore() *Store {
	return &Store{
		databases: skiplist.New[string, *Database]("", "\xff\xff\xff\xff"),
	}
}

// CreateDatabase creates a new database with the given name.
func (s *Store) CreateDatabase(name string) error {
	db := NewDatabase()
	_, err := s.databases.Upsert(name, func(key string, curr *Database, exists bool) (*Database, error) {
		if exists {
			return curr, fmt.Errorf("database already exists")
		}
		return db, nil
	})
	return err
}

// GetDatabase returns the database with the given name, if it exists.
func (s *Store) GetDatabase(name string) (*Database, bool) {
	return s.databases.Find(name)
}

// DeleteDatabase removes the database with the given name.
func (s *Store) DeleteDatabase(name string) (*Database, bool) {
	return s.databases.Remove(name)
}

// ResolvePath navigates the database hierarchy to find the resource at the given path.
// Path components alternate between document names and collection names.
// pathParts should not include the database name (it's already resolved).
// Returns: the containing collection, the document name (if path ends at document),
// and whether the path ends at a collection (trailing slash).
func ResolvePath(db *Database, pathParts []string) (collection *Collection, docName string, err error) {
	col := db.Collection

	if len(pathParts) == 0 {
		// Path is just the database
		return col, "", nil
	}

	// Navigate alternating doc/collection levels
	for i := 0; i < len(pathParts); i++ {
		name := pathParts[i]

		if i == len(pathParts)-1 {
			// Last component - this is the target document name
			return col, name, nil
		}

		// Not the last: must be a document, then a collection
		doc, found := col.Documents.Find(name)
		if !found {
			return nil, "", fmt.Errorf("document not found: %s", name)
		}

		i++ // Move to collection name
		if i >= len(pathParts) {
			// Path ended at a document (odd number of parts after db)
			return col, name, nil
		}

		colName := pathParts[i]
		childCol, found := doc.GetCollection(colName)
		if !found {
			if i == len(pathParts)-1 {
				// This is the last part and it's a collection that doesn't exist
				return nil, "", fmt.Errorf("collection not found: %s", colName)
			}
			return nil, "", fmt.Errorf("collection not found: %s", colName)
		}
		col = childCol
	}

	return col, "", nil
}

// QueryCollection returns documents in the collection within the given interval.
func QueryCollection(col *Collection, low, high string, hasLow, hasHigh bool) ([]skiplist.Pair[string, *Document], error) {
	startKey := ""
	endKey := "\xff\xff\xff\xff"
	if hasLow {
		startKey = low
	}
	if hasHigh {
		endKey = high
	}
	return col.Documents.Query(context.Background(), startKey, endKey)
}

// DocSubscriber tracks subscribers on a specific document.
type DocSubscriber struct {
	EventCh chan Event
}

// DocSubscriptions manages per-document subscribers.
type DocSubscriptions struct {
	mu          sync.RWMutex
	subscribers map[string][]DocSubscriber // path -> subscribers
}

// NewDocSubscriptions creates a new DocSubscriptions.
func NewDocSubscriptions() *DocSubscriptions {
	return &DocSubscriptions{
		subscribers: make(map[string][]DocSubscriber),
	}
}

// Subscribe adds a subscriber for a specific document path.
func (ds *DocSubscriptions) Subscribe(path string, ch chan Event) {
	ds.mu.Lock()
	defer ds.mu.Unlock()
	ds.subscribers[path] = append(ds.subscribers[path], DocSubscriber{EventCh: ch})
}

// Unsubscribe removes a subscriber for a specific document path.
func (ds *DocSubscriptions) Unsubscribe(path string, ch chan Event) {
	ds.mu.Lock()
	defer ds.mu.Unlock()
	subs := ds.subscribers[path]
	for i, sub := range subs {
		if sub.EventCh == ch {
			ds.subscribers[path] = append(subs[:i], subs[i+1:]...)
			if len(ds.subscribers[path]) == 0 {
				delete(ds.subscribers, path)
			}
			return
		}
	}
}

// Notify sends an event to all subscribers of the given document path.
func (ds *DocSubscriptions) Notify(path string, event Event) {
	ds.mu.RLock()
	defer ds.mu.RUnlock()
	for _, sub := range ds.subscribers[path] {
		select {
		case sub.EventCh <- event:
		default:
		}
	}
}

// Package skiplist implements a concurrent skip list with lazy synchronization
// and atomics, providing a generic DBIndex interface for the OwlDB database.
package skiplist

import (
	"cmp"
	"context"
	"math/rand"
	"sync"
	"sync/atomic"
)

const maxLevel = 32

// UpdateCheck is called by Upsert while the node is locked. It receives
// the key, the current value (zero value if !exists), and whether the key
// exists. It returns the new value to store, or an error to abort.
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair holds a key-value pair returned by Query.
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// node is an internal skip list node.
type node[K cmp.Ordered, V any] struct {
	key        K
	value      V
	next       []*node[K, V]
	marked     atomic.Bool
	fullyLinked atomic.Bool
	mu         sync.Mutex
	topLevel   int
}

// SkipList is a concurrent skip list implementing lazy synchronization.
type SkipList[K cmp.Ordered, V any] struct {
	head   *node[K, V]
	tail   *node[K, V]
	maxKey K
	minKey K
	level  int
}

// New creates a new SkipList. minKey and maxKey are sentinel values that
// must be less than all keys and greater than all keys, respectively.
func New[K cmp.Ordered, V any](minKey, maxKey K) *SkipList[K, V] {
	head := &node[K, V]{
		key:      minKey,
		next:     make([]*node[K, V], maxLevel),
		topLevel: maxLevel - 1,
	}
	head.fullyLinked.Store(true)

	tail := &node[K, V]{
		key:      maxKey,
		next:     make([]*node[K, V], maxLevel),
		topLevel: maxLevel - 1,
	}
	tail.fullyLinked.Store(true)

	for i := 0; i < maxLevel; i++ {
		head.next[i] = tail
	}

	return &SkipList[K, V]{
		head:   head,
		tail:   tail,
		maxKey: maxKey,
		minKey: minKey,
		level:  maxLevel,
	}
}

func randomLevel() int {
	level := 0
	for level < maxLevel-1 && rand.Float64() < 0.5 {
		level++
	}
	return level
}

// findNode finds predecessors and successors at each level.
func (sl *SkipList[K, V]) findNode(key K, preds, succs []*node[K, V]) int {
	found := -1
	pred := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.next[level]
		for curr != sl.tail && curr.key < key {
			pred = curr
			curr = pred.next[level]
		}
		if found == -1 && curr != sl.tail && curr.key == key {
			found = level
		}
		preds[level] = pred
		succs[level] = curr
	}
	return found
}

// Find returns the value associated with key, or zero value and false if not found.
func (sl *SkipList[K, V]) Find(key K) (V, bool) {
	preds := make([]*node[K, V], maxLevel)
	succs := make([]*node[K, V], maxLevel)
	found := sl.findNode(key, preds, succs)
	if found != -1 {
		n := succs[found]
		if n.fullyLinked.Load() && !n.marked.Load() {
			return n.value, true
		}
	}
	var zero V
	return zero, false
}

// lockPreds locks unique predecessor nodes from level 0 to topLevel.
// Returns the list of unique nodes that were locked, in lock order.
func lockPreds[K cmp.Ordered, V any](preds []*node[K, V], topLevel int) []*node[K, V] {
	var locked []*node[K, V]
	for level := 0; level <= topLevel; level++ {
		pred := preds[level]
		alreadyLocked := false
		for _, l := range locked {
			if l == pred {
				alreadyLocked = true
				break
			}
		}
		if !alreadyLocked {
			pred.mu.Lock()
			locked = append(locked, pred)
		}
	}
	return locked
}

// unlockAll unlocks all nodes in the slice.
func unlockAll[K cmp.Ordered, V any](locked []*node[K, V]) {
	for _, n := range locked {
		n.mu.Unlock()
	}
}

// Upsert atomically updates or inserts a key using the check function.
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (bool, error) {
	topLevel := randomLevel()
	preds := make([]*node[K, V], maxLevel)
	succs := make([]*node[K, V], maxLevel)

	for {
		found := sl.findNode(key, preds, succs)
		if found != -1 {
			nodeFound := succs[found]
			if nodeFound.marked.Load() {
				// Node is being deleted, retry
				continue
			}
			// Wait until fully linked
			for !nodeFound.fullyLinked.Load() {
			}
			// Lock the node for update
			nodeFound.mu.Lock()
			if nodeFound.marked.Load() {
				nodeFound.mu.Unlock()
				continue
			}
			newVal, err := check(key, nodeFound.value, true)
			if err != nil {
				nodeFound.mu.Unlock()
				return false, err
			}
			nodeFound.value = newVal
			nodeFound.mu.Unlock()
			return true, nil
		}

		// Need to insert - lock unique predecessors
		locked := lockPreds(preds, topLevel)

		// Validate that predecessors are still valid
		valid := true
		for level := 0; level <= topLevel; level++ {
			pred := preds[level]
			succ := succs[level]
			if pred.marked.Load() || succ.marked.Load() || pred.next[level] != succ {
				valid = false
				break
			}
		}

		if !valid {
			unlockAll(locked)
			continue
		}

		var zero V
		newVal, err := check(key, zero, false)
		if err != nil {
			unlockAll(locked)
			return false, err
		}

		newNode := &node[K, V]{
			key:      key,
			value:    newVal,
			next:     make([]*node[K, V], topLevel+1),
			topLevel: topLevel,
		}

		for level := 0; level <= topLevel; level++ {
			newNode.next[level] = succs[level]
			preds[level].next[level] = newNode
		}
		newNode.fullyLinked.Store(true)

		unlockAll(locked)
		return false, nil
	}
}

// Remove removes the key from the skip list, returning its value and true,
// or zero value and false if not found.
func (sl *SkipList[K, V]) Remove(key K) (V, bool) {
	var victim *node[K, V]
	isMarked := false
	topLevel := -1
	preds := make([]*node[K, V], maxLevel)
	succs := make([]*node[K, V], maxLevel)
	var zero V

	for {
		found := sl.findNode(key, preds, succs)
		if isMarked || (found != -1 && okToDelete(succs[found], found)) {
			if !isMarked {
				victim = succs[found]
				topLevel = victim.topLevel
				victim.mu.Lock()
				if victim.marked.Load() {
					victim.mu.Unlock()
					return zero, false
				}
				victim.marked.Store(true)
				isMarked = true
			}

			// Lock unique predecessors
			locked := lockPreds(preds, topLevel)

			// Validate
			valid := true
			for level := 0; level <= topLevel; level++ {
				pred := preds[level]
				if pred.marked.Load() || pred.next[level] != victim {
					valid = false
					break
				}
			}

			if !valid {
				unlockAll(locked)
				continue
			}

			for level := topLevel; level >= 0; level-- {
				preds[level].next[level] = victim.next[level]
			}
			victim.mu.Unlock()
			unlockAll(locked)
			return victim.value, true
		}
		return zero, false
	}
}

func okToDelete[K cmp.Ordered, V any](n *node[K, V], found int) bool {
	return n.fullyLinked.Load() && n.topLevel == found && !n.marked.Load()
}

// Query returns all elements with keys in [start, end] in order.
func (sl *SkipList[K, V]) Query(ctx context.Context, start, end K) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	// Find the starting point
	curr := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		for curr.next[level] != sl.tail && curr.next[level].key < start {
			curr = curr.next[level]
		}
	}
	curr = curr.next[0]

	for curr != sl.tail && curr.key <= end {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if curr.fullyLinked.Load() && !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}

	return results, nil
}

// ForEach calls fn for each element in the skip list in order.
// If fn returns false, iteration stops.
func (sl *SkipList[K, V]) ForEach(fn func(key K, value V) bool) {
	curr := sl.head.next[0]
	for curr != sl.tail {
		if curr.fullyLinked.Load() && !curr.marked.Load() {
			if !fn(curr.key, curr.value) {
				return
			}
		}
		curr = curr.next[0]
	}
}

