+// Package auth implements bearer token authentication for OwlDB.
+package auth
+
+import (
+	"crypto/rand"
+	"encoding/hex"
+	"encoding/json"
+	"fmt"
+	"os"
+	"sync"
+	"time"
+)
+
+// tokenEntry stores info about a token.
+type tokenEntry struct {
+	username  string
+	expiresAt time.Time
+}
+
+// Manager manages authentication tokens.
+type Manager struct {
+	mu     sync.RWMutex
+	tokens map[string]tokenEntry // token -> entry
+}
+
+// NewManager creates a new auth manager.
+func NewManager() *Manager {
+	return &Manager{
+		tokens: make(map[string]tokenEntry),
+	}
+}
+
+// LoadTokenFile loads pre-configured tokens from a JSON file.
+// The file maps usernames to tokens.
+func (m *Manager) LoadTokenFile(filename string) error {
+	data, err := os.ReadFile(filename)
+	if err != nil {
+		return fmt.Errorf("failed to read token file: %w", err)
+	}
+
+	var tokenMap map[string]string
+	if err := json.Unmarshal(data, &tokenMap); err != nil {
+		return fmt.Errorf("failed to parse token file: %w", err)
+	}
+
+	m.mu.Lock()
+	defer m.mu.Unlock()
+
+	for username, token := range tokenMap {
+		m.tokens[token] = tokenEntry{
+			username:  username,
+			expiresAt: time.Now().Add(24 * time.Hour),
+		}
+	}
+	return nil
+}
+
+// Login creates a new token for the given username.
+func (m *Manager) Login(username string) (string, error) {
+	token, err := generateToken()
+	if err != nil {
+		return "", err
+	}
+
+	m.mu.Lock()
+	defer m.mu.Unlock()
+
+	m.tokens[token] = tokenEntry{
+		username:  username,
+		expiresAt: time.Now().Add(1 * time.Hour),
+	}
+	return token, nil
+}
+
+// Logout invalidates the given token.
+func (m *Manager) Logout(token string) bool {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+
+	if _, ok := m.tokens[token]; ok {
+		delete(m.tokens, token)
+		return true
+	}
+	return false
+}
+
+// ValidateToken checks if a token is valid and not expired.
+// Returns the username associated with the token, or an error.
+func (m *Manager) ValidateToken(token string) (string, bool) {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+
+	entry, ok := m.tokens[token]
+	if !ok {
+		return "", false
+	}
+	if time.Now().After(entry.expiresAt) {
+		return "", false
+	}
+	return entry.username, true
+}
+
+// generateToken creates a cryptographically random token.
+func generateToken() (string, error) {
+	b := make([]byte, 16)
+	_, err := rand.Read(b)
+	if err != nil {
+		return "", err
+	}
+	return hex.EncodeToString(b), nil
+}
