+// Document operations
+
+func (s *Server) handlePutDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string, mode string) {
+	db, ok := s.store.GetDatabase(dbName)
+	if !ok {
+		writeError(w, http.StatusNotFound, "Database does not exist")
+		return
+	}
+
+	// Read body
+	body, err := io.ReadAll(r.Body)
+	if err != nil {
+		writeError(w, http.StatusBadRequest, "Failed to read request body")
+		return
+	}
+
+	// Validate against schema
+	if s.schema != nil && len(body) > 0 {
+		var jv jsondata.JSONValue
+		if err := json.Unmarshal(body, &jv); err != nil {
+			writeError(w, http.StatusBadRequest, "Invalid JSON")
+			return
+		}
+		if err := jv.Validate(s.schema); err != nil {
+			writeError(w, http.StatusBadRequest, fmt.Sprintf("Schema validation failed: %s", err))
+			return
+		}
+	}
+
+	// Navigate to the containing collection
+	col := db.Collection
+	docName := pathParts[len(pathParts)-1]
+
+	if len(pathParts) > 1 {
+		// Navigate through the path to find the parent collection
+		parentParts := pathParts[:len(pathParts)-1]
+		currentCol := db.Collection
+		for i := 0; i < len(parentParts); i += 2 {
+			pDocName := parentParts[i]
+			doc, found := currentCol.Documents.Find(pDocName)
+			if !found {
+				writeError(w, http.StatusNotFound, "Collection does not exist")
+				return
+			}
+			if i+1 >= len(parentParts) {
+				writeError(w, http.StatusNotFound, "Collection does not exist")
+				return
+			}
+			colName := parentParts[i+1]
+			childCol, found := doc.GetCollection(colName)
+			if !found {
+				writeError(w, http.StatusNotFound, "Collection does not exist")
+				return
+			}
+			currentCol = childCol
+		}
+		col = currentCol
+	}
+
+	docPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
+	noOverwrite := mode == "nooverwrite"
+
+	var statusCode int
+	newDoc := document.NewDocument(body, username)
+
+	_, err = col.Documents.Upsert(docName, func(key string, curr *document.Document, exists bool) (*document.Document, error) {
+		if exists && noOverwrite {
+			return curr, fmt.Errorf("document already exists")
+		}
+		if exists {
+			// Overwrite: preserve createdBy and createdAt
+			curr.UpdateData(body, username)
+			statusCode = http.StatusOK
+			return curr, nil
+		}
+		statusCode = http.StatusCreated
+		return newDoc, nil
+	})
+
+	if err != nil {
+		if noOverwrite {
+			writeError(w, http.StatusPreconditionFailed, "Document already exists")
+		} else {
+			writeError(w, http.StatusInternalServerError, err.Error())
+		}
+		return
+	}
+
+	// Notify subscribers
+	var doc *document.Document
+	if statusCode == http.StatusOK {
+		doc, _ = col.Documents.Find(docName)
+	} else {
+		doc = newDoc
+	}
+	s.notifyDocUpdate(docPath, docName, doc, col)
+
+	w.Header().Set("Location", docPath)
+	writeJSON(w, statusCode, map[string]string{"uri": docPath})
+}
+
+func (s *Server) handleGetDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string) {
+	db, ok := s.store.GetDatabase(dbName)
+	if !ok {
+		writeError(w, http.StatusNotFound, "Database does not exist")
+		return
+	}
+
+	col, docName, err := resolveToDoc(db, pathParts)
+	if err != nil {
+		writeError(w, http.StatusNotFound, err.Error())
+		return
+	}
+
+	doc, found := col.Documents.Find(docName)
+	if !found {
+		writeError(w, http.StatusNotFound, "Document does not exist")
+		return
+	}
+
+	docPath := "/v1/" + dbName + "/" + strings.Join(pathParts, "/")
+	result := buildDocResponse(docPath, doc)
+	writeJSON(w, http.StatusOK, result)
+}
