+func (s *Server) handlePostDocument(w http.ResponseWriter, r *http.Request, dbName string, pathParts []string, username string) {
+	db, ok := s.store.GetDatabase(dbName)
+	if !ok {
+		writeError(w, http.StatusNotFound, "Database does not exist")
